# DiagnoseAHORunFailure: Provides comprehensive diagnostic information for a failed workflow run.

    This function collects multiple sources of diagnostic information including:
    - Run details and failure reason
    - Engine logs from CloudWatch
    - Run manifest logs containing workflow summary and resource metrics (when detailed=True)
    - Task logs from all failed tasks
    - Actionable recommendations for troubleshooting

    Args:
        ctx: MCP context for error reporting
        run_id: ID of the failed run
        detailed: If False (default), excludes manifest logs and limits engine/task logs to last 50 lines
                 from 15 minutes before stop time to 5 minutes after. If True, includes all logs.

    Returns:
        Dictionary containing comprehensive diagnostic information including:
        - runId: The run identifier
        - status: Current run status
        - failureReason: AWS-provided failure reason
        - runUuid: Run UUID for log stream identification
        - engineLogs: Engine execution logs
        - manifestLogs: Run manifest logs with workflow summary (only when detailed=True)
        - failedTasks: List of failed tasks with their logs
        - recommendations: Troubleshooting recommendations
    
# Usage: DiagnoseAHORunFailure <run_id> <detailed>
DiagnoseAHORunFailure() {
    aws omics get-run \
        --id "$RUN_ID" \
        --export "$DETAILED"
}


# LintAHOWorkflowDefinition: Lint WDL or CWL workflow definitions and return validation findings.

    This tool validates workflow definitions using appropriate linting tools:
    - WDL workflows: Uses miniwdl package for parsing and validation
    - CWL workflows: Uses cwltool package for parsing and validation

    The tool checks for:
    - Syntax errors and parsing issues
    - Missing required fields (inputs, outputs, steps)
    - Runtime requirements for tasks
    - Common workflow structure issues

    Args:
        ctx: MCP context for error reporting
        workflow_content: The workflow definition content to lint
        workflow_format: The workflow format ('wdl' or 'cwl')
        filename: Optional filename for context in error messages

    Returns:
        Dictionary containing:
        - status: 'success' or 'error'
        - format: The workflow format that was linted
        - filename: The filename that was processed (optional)
        - linter: Name of the linting tool used
        - raw_output: Raw output from the linter command execution
    
# Usage: LintAHOWorkflowDefinition <workflow_content> <workflow_format> <filename>
LintAHOWorkflowDefinition() {
    aws omics validate-workflow-definition \
        --workflow-definition "$WORKFLOW_CONTENT" \
        --type "$WORKFLOW_FORMAT" \
        --name "$FILENAME"
}


# LintAHOWorkflowBundle: Lint multi-file WDL or CWL workflow bundles and return validation findings.

    This tool validates multi-file workflow bundles using appropriate linting tools:
    - WDL workflows: Uses miniwdl package for parsing and validation with import support
    - CWL workflows: Uses cwltool package for parsing and validation with dependency resolution

    The tool creates a temporary directory structure that preserves the relative file paths,
    allowing proper resolution of imports and dependencies between workflow files.

    The tool checks for:
    - Syntax errors and parsing issues across all files
    - Missing required fields (inputs, outputs, steps)
    - Import/dependency resolution
    - Runtime requirements for tasks
    - Common workflow structure issues

    Args:
        ctx: MCP context for error reporting
        workflow_files: Dictionary mapping relative file paths to their content
        workflow_format: The workflow format ('wdl' or 'cwl')
        main_workflow_file: Path to the main workflow file within the bundle

    Returns:
        Dictionary containing:
        - status: 'success' or 'error'
        - format: The workflow format that was linted
        - main_file: The main workflow file that was processed
        - files_processed: List of all files that were processed
        - linter: Name of the linting tool used
        - raw_output: Raw output from the linter command execution
    
# Usage: LintAHOWorkflowBundle <workflow_files> <workflow_format> <main_workflow_file>
LintAHOWorkflowBundle() {
    aws omics validate-workflow-definition \
        --workflow-definition "$WORKFLOW_FILES" \
        --type "$WORKFLOW_FORMAT" \
        --main-workflow-path "$MAIN_WORKFLOW_FILE"
}


